import{_ as t,o,c as a,a3 as i}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Authentication — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Authentication — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/authentication"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Authentication — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/authentication"}]]},"headers":[],"relativePath":"deployment/authentication.md","filePath":"deployment/authentication.md","lastUpdated":1784902400000}'),n={name:"deployment/authentication.md"};function r(s,e,d,c,l,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="authentication-—-production-guide" tabindex="-1">Authentication — Production Guide <a class="header-anchor" href="#authentication-—-production-guide" aria-label="Permalink to &quot;Authentication — Production Guide&quot;">​</a></h1><h2 id="mail-configuration" tabindex="-1">Mail configuration <a class="header-anchor" href="#mail-configuration" aria-label="Permalink to &quot;Mail configuration&quot;">​</a></h2><p>Password reset and invite emails require a working mailer.</p><p>Configure via Central <strong>Settings → Mail</strong> (or env fallbacks):</p><ul><li><code>MAIL_MAILER</code>, <code>MAIL_HOST</code>, <code>MAIL_PORT</code>, <code>MAIL_USERNAME</code>, <code>MAIL_PASSWORD</code></li><li>From name/address (system settings override runtime config)</li></ul><p>Send a test message from Settings before go-live.</p><h2 id="password-reset-configuration" tabindex="-1">Password reset configuration <a class="header-anchor" href="#password-reset-configuration" aria-label="Permalink to &quot;Password reset configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td><code>FRONTEND_URL</code></td><td>Absolute SPA URL used in reset/invite email links</td></tr><tr><td><code>auth.passwords.users.expire</code></td><td>Tenant reset token lifetime (minutes)</td></tr><tr><td><code>auth.passwords.central_users.expire</code></td><td>Central reset token lifetime (minutes)</td></tr></tbody></table><p>Tenant links: <code>{FRONTEND_URL}/reset-password/{token}?email=</code><br> Central links: <code>{FRONTEND_URL}/central/reset-password/{token}?email=</code></p><h2 id="password-policy" tabindex="-1">Password policy <a class="header-anchor" href="#password-policy" aria-label="Permalink to &quot;Password policy&quot;">​</a></h2><p>Central Settings → Security:</p><ul><li><code>password_min_length</code></li><li><code>password_require_special</code></li></ul><p>Enforced by <code>App\\Rules\\PasswordRule</code> on registration, reset, and change-password flows. Do not duplicate validation in clients beyond UX hints.</p><h2 id="authentication-security" tabindex="-1">Authentication security <a class="header-anchor" href="#authentication-security" aria-label="Permalink to &quot;Authentication security&quot;">​</a></h2><ul><li>Separate Sanctum guards: <code>central-api</code> / <code>tenant-api</code></li><li>Separate SPA token storage keys (central vs tenant)</li><li>Tenant workspace resolution is hybrid: host/domain first, then token context, then an explicit Workspace value or <code>X-Tenant-Domain</code> header. This supports the shared <code>/login</code> today and future custom workspace domains without changing API paths.</li><li>Do not persist a tenant/workspace selection in <code>localStorage</code>; the SPA resolves it from the active host or the current login/request.</li><li>Login throttling (<code>auth-login</code>, 5/minute)</li><li>Forgot/reset throttling (<code>6,1</code>)</li><li>Soft-deleted and suspended users receive a generic credentials error</li><li>Email verification is enforced for protected Central and tenant application endpoints; the SPA <code>VerifyEmailGate</code> <strong>Sign out</strong> action clears the session and navigates to the context login route</li><li>CSRF: SPA uses Bearer tokens; stateful Sanctum cookie auth remains available when configured</li><li>Registration gated by <code>registration_enabled</code></li></ul><h2 id="session-configuration" tabindex="-1">Session configuration <a class="header-anchor" href="#session-configuration" aria-label="Permalink to &quot;Session configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Notes</th></tr></thead><tbody><tr><td><code>SESSION_DRIVER</code></td><td>Prefer <code>database</code> in production</td></tr><tr><td><code>SESSION_LIFETIME</code></td><td>Overridden at runtime by <code>session_lifetime_minutes</code> system setting</td></tr><tr><td><code>SESSION_ENCRYPT</code></td><td>Enable in production if cookies are used</td></tr><tr><td><code>SESSION_DOMAIN</code></td><td>Set for shared parent domain if using cookie SPA auth</td></tr></tbody></table><p>API auth for the React apps is primarily Bearer token based; remember-me stores the token in <code>localStorage</code> vs <code>sessionStorage</code>.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>[ ] <code>FRONTEND_URL</code> points at the production SPA</li><li>[ ] Mail delivers reset emails to a real inbox</li><li>[ ] Registration enabled/disabled matches business policy</li><li>[ ] Password policy matches compliance requirements</li><li>[ ] Rate limiters confirmed under load</li><li>[ ] Central (<code>/central/login</code>) and tenant (<code>/login</code>, including Workspace entry) both verified</li><li>[ ] Workspace host resolution verified for a platform subdomain and at least one custom-domain candidate</li><li>[ ] Central and tenant email-verification gates verified</li></ul>',20)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
